const fs = require('fs');
const path = require('path');

function readLogFile(baseDir, userFilename) {
  // Allowlist of valid filenames
  const allowedFiles = ['app.log', 'error.log', 'access.log', 'debug.log'];
  
  // Validate input
  if (!userFilename || typeof userFilename !== 'string') {
    throw new Error('Invalid filename provided');
  }
  
  // Check if filename is in allowlist
  if (!allowedFiles.includes(userFilename)) {
    throw new Error('Filename not allowed');
  }
  
  // Resolve the full path
  const fullPath = path.resolve(baseDir, userFilename);
  
  // Verify path is within base directory
  const resolvedBaseDir = path.resolve(baseDir);
  if (!fullPath.startsWith(resolvedBaseDir + path.sep)) {
    throw new Error('Access denied: File path is outside allowed directory');
  }
  
  // Check for absolute paths
  if (path.isAbsolute(userFilename)) {
    throw new Error('Absolute paths are not allowed');
  }
  
  // Check for traversal segments
  if (userFilename.includes('..') || userFilename.startsWith('/')) {
    throw new Error('Path traversal detected');
  }
  
  try {
    return fs.readFileSync(fullPath, 'utf8');
  } catch (error) {
    throw new Error('Failed to read file: ' + error.message);
  }
}